    'topic.calibration': 'Kalibrierung',
    'topic.batch_records': 'Chargenaufzeichnungen',
    'topic.visual_inspection': 'Sichtprüfung',
    'topic.defect_class': 'Fehlerklassifizierung',
    'topic.sop_compliance': 'SOP-Konformität',
    'topic.risk_thinking': 'Risikobasiertes Denken',
    'start.how_content': '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px 20px;line-height:1.9;"><div>🔍 <strong style="color:var(--text);">Hotspots untersuchen</strong> in jedem Bereich, um Hinweise zu finden und Gegenstände zu sammeln</div><div>🎒 <strong style="color:var(--text);">Gegenstand auswählen</strong> aus Ihrem Inventar, dann auf einen Hotspot klicken, um ihn zu nutzen</div><div>🧩 <strong style="color:var(--text);">Rätsel lösen</strong> — jede Antwort basiert auf echten Qualitätsprinzipien</div><div>📋 <strong style="color:var(--text);">Feldnotizen prüfen</strong> — Hinweise und Fakten werden automatisch aufgezeichnet</div><div>💬 <strong style="color:var(--text);">Gruppenchat nutzen</strong> — koordinieren Sie sich mit Ihrem Team in Echtzeit</div><div>🔑 <strong style="color:var(--text);">Codes gemeinsam bestätigen</strong> — wichtige Meilensteine erfordern, dass alle Mitglieder den Code eingeben</div></div><div style="margin-top:10px;padding:8px 12px;background:rgba(0,153,230,0.07);border-left:3px solid var(--accent);border-radius:2px;font-size:0.77rem;color:var(--dim);line-height:1.7;">Es gibt <strong style="color:var(--text);">5 Bereiche</strong> und <strong style="color:var(--text);">11 Rätsel</strong>, die in <strong style="color:var(--text);">30 Minuten</strong> abgeschlossen werden müssen. Bereiche werden freigeschaltet, wenn Sie Fortschritte erzielen — Sie können nicht vorspringen.</div>',
    'start.rules_content': '<table style="width:100%;border-collapse:collapse;"><tr style="border-bottom:1px solid var(--border);"><td style="padding:7px 8px 7px 0;width:28px;font-size:1rem;">👥</td><td style="padding:7px 0;color:var(--dim);"><strong style="color:var(--text);">Teamgröße:</strong> 3 – 5 Mitglieder. Alle müssen verbunden sein, bevor das Spiel beginnt.</td></tr><tr style="border-bottom:1px solid var(--border);"><td style="padding:7px 8px 7px 0;font-size:1rem;">⏱️</td><td style="padding:7px 0;color:var(--dim);"><strong style="color:var(--text);">Gleichzeitiger Start:</strong> Jeder Spieler muss auf <em>„Ich bin bereit"</em> klicken. Der Timer startet für alle gleichzeitig.</td></tr><tr style="border-bottom:1px solid var(--border);"><td style="padding:7px 8px 7px 0;font-size:1rem;">🔑</td><td style="padding:7px 0;color:var(--dim);"><strong style="color:var(--text);">Teambestätigung:</strong> An wichtigen Kontrollpunkten wird der Code für alle angezeigt — jedes Mitglied muss ihn eingeben, um fortzufahren.</td></tr><tr style="border-bottom:1px solid var(--border);"><td style="padding:7px 8px 7px 0;font-size:1rem;">🚪</td><td style="padding:7px 0;color:var(--dim);"><strong style="color:var(--text);">Bereichssperren:</strong> Jeder Bereich ist gesperrt, bis die vorherige Aufgabe abgeschlossen ist — Aufgaben in der richtigen Reihenfolge erledigen.</td></tr><tr style="border-bottom:1px solid var(--border);"><td style="padding:7px 8px 7px 0;font-size:1rem;">❌</td><td style="padding:7px 0;color:var(--dim);"><strong style="color:var(--text);">Falsche Antworten:</strong> Jede falsche Antwort zieht <strong style="color:var(--danger);">50 Punkte</strong> von Ihrer Endpunktzahl ab — denken Sie nach, bevor Sie einreichen.</td></tr><tr style="border-bottom:1px solid var(--border);"><td style="padding:7px 8px 7px 0;font-size:1rem;">💡</td><td style="padding:7px 0;color:var(--dim);"><strong style="color:var(--text);">Hinweise:</strong> Jeder Bereich hat einen Hinweis. Ein Hinweis kostet <strong style="color:var(--danger);">−60 Sekunden</strong> und <strong style="color:var(--danger);">−50 Punkte</strong>. Hinweise sind subtil — sie geben die Antwort nicht direkt.</td></tr><tr style=""><td style="padding:7px 8px 7px 0;font-size:1rem;">🏁</td><td style="padding:7px 0;color:var(--dim);"><strong style="color:var(--text);">Ein Versuch:</strong> Jede Gruppe spielt einmal. Ergebnisse sind endgültig und werden in der Rangliste veröffentlicht.</td></tr></table>',
    'start.scoring_content': '<table style="width:100%;border-collapse:collapse;margin-bottom:10px;"><thead><tr style="border-bottom:1px solid var(--border);"><th style="text-align:left;font-size:0.65rem;text-transform:uppercase;letter-spacing:1.5px;color:var(--dim);padding:5px 0;">Was</th><th style="text-align:right;font-size:0.65rem;text-transform:uppercase;letter-spacing:1.5px;color:var(--dim);padding:5px 0;">Punkte</th></tr></thead><tbody><tr style="border-bottom:1px solid #14162a;"><td style="padding:8px 0;color:var(--dim);">✅ Jedes gelöste Rätsel</td><td style="padding:8px 0;text-align:right;color:var(--accent2);font-weight:bold;">+200 Pkt.</td></tr><tr style="border-bottom:1px solid #14162a;"><td style="padding:8px 0;color:var(--dim);">⏱️ Jede verbleibende Sekunde <em>(nur bei Sieg)</em></td><td style="padding:8px 0;text-align:right;color:var(--accent2);font-weight:bold;">+2 Pkt. / Sek.</td></tr><tr style="border-bottom:1px solid #14162a;"><td style="padding:8px 0;color:var(--dim);">❌ Jede falsche Antwort</td><td style="padding:8px 0;text-align:right;color:var(--danger);font-weight:bold;">−50 Pkt.</td></tr><tr style=""><td style="padding:8px 0;color:var(--dim);">💡 Hinweis verwenden</td><td style="padding:8px 0;text-align:right;color:var(--danger);font-weight:bold;">−50 Pkt. &amp; −60s</td></tr></tbody></table><div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;"><div style="background:#0a0c18;border:1px solid var(--border);border-radius:6px;padding:10px 14px;text-align:center;"><div style="font-size:0.65rem;text-transform:uppercase;letter-spacing:1.5px;color:var(--dim);margin-bottom:4px;">Max. Rätselpunkte</div><div style="font-size:1.2rem;font-weight:bold;color:var(--accent2);">2,200</div><div style="font-size:0.68rem;color:var(--dim);">11 × 200</div></div><div style="background:#0a0c18;border:1px solid var(--border);border-radius:6px;padding:10px 14px;text-align:center;"><div style="font-size:0.65rem;text-transform:uppercase;letter-spacing:1.5px;color:var(--dim);margin-bottom:4px;">Max. Zeitbonus</div><div style="font-size:1.2rem;font-weight:bold;color:var(--accent2);">3,600</div><div style="font-size:0.68rem;color:var(--dim);">1.800 Sek. × 2</div></div></div><div style="margin-top:8px;padding:8px 12px;background:rgba(255,215,0,0.06);border:1px solid rgba(255,215,0,0.25);border-radius:4px;text-align:center;font-size:0.78rem;color:#ffd700;">🏆 Maximal mögliche Punktzahl: <strong>5.800 Pkt.</strong> — alle Rätsel gelöst, keine falschen Antworten, keine Hinweise, sofortiger Abschluss</div>',
